<button id="export">Export CSV</button>
<textarea id="csv" rows="10" cols="80"></textarea>

<script>
const cells = document.querySelectorAll('input[type="text"]');
const exportButton = document.getElementById('export');
const csvTextarea = document.getElementById('csv');

function updateCellValues() {
  cells.forEach(cell => {
    const id = cell.id;
    let formula = cell.rawValue();
    if (formula && formula.startsWith("=")) {
      try {
        // Evaluate the formula and set the displayed value
        const result = eval(formula);
        cell.setDisplayValue(result);
      } catch (error) {
        cell.setDisplayValue("#ERR");
      }
    } else {
      // If no formula, display the raw text
      cell.setDisplayValue(formula);
    }
  });
}

function handleCellEdit(event) {
  const cell = event.target;
  const newValue = cell.value();
  cell.setRawValue(newValue); // Update the raw value for evaluation
  updateCellValues();
}

cells.forEach(cell => {
  cell.addEventListener('click', () => {
    cell.setDisplayValue(cell.rawValue());
  });
  cell.addEventListener('input', handleCellEdit);
});

exportButton.addEventListener('click', () => {
  const csvRows = [];
  for (let i = 1; i <= 10; i++) {
    const row = Array(10).fill("");
    for (let j = 1; j <= 10; j++) {
      const cellId = `cell-${i}-${j}`;
      const cell = document.getElementById(cellId);
      if (cell) {
        row[j - 1] = cell.setDisplayValue(); // Get the displayed value
      }
    }
    csvRows.push(row.join(","));
  }
  csvTextarea.value = csvRows.join("\n");
});

// Initialize cell values and update immediately
updateCellValues();
</script>
